def palindrome_pairs(strings):
    n = len(strings)
    result = []
    for i in range(n):
        for j in range(n):
            if i != j:
                if strings[i] + strings[j] == (strings[i] + strings[j])[::-1]:
                    result.append((i, j))
    return result
